from __future__ import annotations

from dataclasses import dataclass
from random import Random
from typing import Final

WALL: Final[str] = "#"
FLOOR: Final[str] = "."
PLAYER: Final[str] = "@"
MONSTER: Final[str] = "g"

@dataclass(frozen=True)
class Point:
    x: int
    y: int

@dataclass
class Fighter:
    hp: int
    power: int

    @property
    def alive(self) -> bool:
        return self.hp > 0

@dataclass
class Entity:
    name: str
    pos: Point
    fighter: Fighter | None = None

@dataclass(frozen=True)
class Room:
    x1: int
    y1: int
    x2: int
    y2: int

    @property
    def center(self) -> Point:
        return Point((self.x1 + self.x2) // 2, (self.y1 + self.y2) // 2)

    def intersects(self, other: Room) -> bool:
        return self.x1 <= other.x2 and self.x2 >= other.x1 and self.y1 <= other.y2 and self.y2 >= other.y1

@dataclass
class GameMap:
    width: int
    height: int
    tiles: list[list[str]]

    @classmethod
    def filled(cls, width: int, height: int, tile: str) -> GameMap:
        return cls(width, height, [[tile for _ in range(width)] for _ in range(height)])

    def in_bounds(self, point: Point) -> bool:
        return 0 <= point.x < self.width and 0 <= point.y < self.height

    def is_walkable(self, point: Point) -> bool:
        return self.in_bounds(point) and self.tiles[point.y][point.x] == FLOOR

    def carve_room(self, room: Room) -> None:
        for y in range(room.y1, room.y2 + 1):
            for x in range(room.x1, room.x2 + 1):
                self.tiles[y][x] = FLOOR

    def carve_h_tunnel(self, x1: int, x2: int, y: int) -> None:
        for x in range(min(x1, x2), max(x1, x2) + 1):
            self.tiles[y][x] = FLOOR

    def carve_v_tunnel(self, y1: int, y2: int, x: int) -> None:
        for y in range(min(y1, y2), max(y1, y2) + 1):
            self.tiles[y][x] = FLOOR

@dataclass
class Game:
    game_map: GameMap
    player: Entity
    monsters: list[Entity]
    log: list[str]

    def entity_at(self, point: Point) -> Entity | None:
        for monster in self.monsters:
            if monster.pos == point and monster.fighter is not None and monster.fighter.alive:
                return monster
        return None

    def move_player(self, dx: int, dy: int) -> None:
        destination = Point(self.player.pos.x + dx, self.player.pos.y + dy)
        target = self.entity_at(destination)
        if target is not None:
            self.attack(self.player, target)
        elif self.game_map.is_walkable(destination):
            self.player.pos = destination

    def attack(self, attacker: Entity, defender: Entity) -> None:
        if attacker.fighter is None or defender.fighter is None:
            return
        defender.fighter.hp -= attacker.fighter.power
        self.log.append(f"{attacker.name} hits {defender.name} for {attacker.fighter.power} damage")
        if defender.fighter.hp <= 0:
            self.log.append(f"{defender.name} dies")

def generate_dungeon(width: int, height: int, seed: int) -> tuple[GameMap, list[Room]]:
    rng = Random(seed)
    game_map = GameMap.filled(width, height, WALL)
    rooms: list[Room] = []
    for _ in range(30):
        room_width = rng.randint(4, 8)
        room_height = rng.randint(4, 6)
        x = rng.randint(1, width - room_width - 2)
        y = rng.randint(1, height - room_height - 2)
        room = Room(x, y, x + room_width - 1, y + room_height - 1)
        if any(room.intersects(existing) for existing in rooms):
            continue
        game_map.carve_room(room)
        if rooms:
            previous = rooms[-1].center
            current = room.center
            game_map.carve_h_tunnel(previous.x, current.x, previous.y)
            game_map.carve_v_tunnel(previous.y, current.y, current.x)
        rooms.append(room)
    if not rooms:
        raise RuntimeError("failed to generate at least one room")
    return game_map, rooms

def new_game(width: int = 40, height: int = 24, seed: int = 1) -> Game:
    game_map, rooms = generate_dungeon(width, height, seed)
    player = Entity("player", rooms[0].center, Fighter(hp=20, power=5))
    monsters = [Entity("goblin", room.center, Fighter(hp=6, power=2)) for room in rooms[1:8]]
    return Game(game_map, player, monsters, [])

def run_headless(seed: int, turns: int) -> Game:
    game = new_game(seed=seed)
    rng = Random(seed + 2000)
    moves = [Point(1, 0), Point(0, 1), Point(-1, 0), Point(0, -1)]
    for _ in range(turns):
        move = rng.choice(moves)
        game.move_player(move.x, move.y)
    return game

if __name__ == "__main__":
    run_headless(seed=123, turns=100)
