from __future__ import annotations

from dataclasses import dataclass
from heapq import heappop, heappush

@dataclass(frozen=True, order=True)
class Point:
    x: int
    y: int

def manhattan(a: Point, b: Point) -> int:
    return abs(a.x - b.x) + abs(a.y - b.y)

def neighbors(point: Point) -> tuple[Point, Point, Point, Point]:
    return (Point(point.x + 1, point.y), Point(point.x, point.y + 1), Point(point.x - 1, point.y), Point(point.x, point.y - 1))

def reconstruct_path(came_from: dict[Point, Point], start: Point, goal: Point) -> list[Point]:
    path: list[Point] = []
    current = goal
    while current != start:
        path.append(current)
        current = came_from[current]
    path.reverse()
    return path

def astar(start: Point, goal: Point, width: int, height: int, blocked: set[Point]) -> list[Point] | None:
    if start == goal:
        return []
    if goal in blocked:
        return None
    frontier: list[tuple[int, int, Point]] = []
    counter = 0
    heappush(frontier, (0, counter, start))
    came_from: dict[Point, Point] = {}
    cost_so_far: dict[Point, int] = {start: 0}
    while frontier:
        _, _, current = heappop(frontier)
        if current == goal:
            return reconstruct_path(came_from, start, goal)
        for next_point in neighbors(current):
            if not (0 <= next_point.x < width and 0 <= next_point.y < height):
                continue
            if next_point in blocked:
                continue
            new_cost = cost_so_far[current] + 1
            old_cost = cost_so_far.get(next_point)
            if old_cost is not None and new_cost >= old_cost:
                continue
            cost_so_far[next_point] = new_cost
            came_from[next_point] = current
            counter += 1
            priority = new_cost + manhattan(next_point, goal)
            heappush(frontier, (priority, counter, next_point))
    return None

def test_astar_returns_empty_path_when_start_is_goal() -> None:
    start = Point(2, 2)
    assert astar(start, start, 5, 5, set()) == []

def test_astar_finds_straight_path() -> None:
    assert astar(Point(0, 0), Point(3, 0), 5, 5, set()) == [Point(1, 0), Point(2, 0), Point(3, 0)]

def test_astar_routes_around_wall() -> None:
    blocked = {Point(1, 0), Point(1, 1)}
    path = astar(Point(0, 0), Point(2, 0), 4, 4, blocked)
    assert path is not None
    assert path[-1] == Point(2, 0)
    assert not any(point in blocked for point in path)

def test_astar_returns_none_when_goal_is_blocked() -> None:
    assert astar(Point(0, 0), Point(1, 0), 3, 3, {Point(1, 0)}) is None
